178	// TestLand_HappyPath_FastForward verifies the fast-forward path: currentTip
179	// == BaseRev → target branch is advanced directly to ResultRev with no
180	// merge commit. The worker's commit becomes the new tip unchanged.
181	func TestLand_HappyPath_FastForward(t *testing.T) {
182		r := newLandTestRepo(t)
183		ops := RealLandingGitOps{}
184	
185		// Worker commit at current main.
186		resultSHA := r.commitOn(r.baseSHA, "feature.txt", "hello\n", "feat: hello")
187	
188		req := LandRequest{
189			WorktreeDir:  r.dir,
190			BaseRev:      r.baseSHA,
191			ResultRev:    resultSHA,
192			BeadID:       "ddx-land-happy",
193			AttemptID:    "20260414T000000-aabb",
194			TargetBranch: "main",
195		}
196		land, err := Land(r.dir, req, ops)
197		if err != nil {
198			t.Fatalf("Land: %v", err)
199		}
200		if land.Status != "landed" {
201			t.Fatalf("expected status=landed, got %q (reason=%q)", land.Status, land.Reason)
202		}
203		if land.Merged {
204			t.Errorf("expected Merged=false on fast path, got true")
205		}
206		if land.NewTip != resultSHA {
207			t.Errorf("expected NewTip=%s, got %s", resultSHA, land.NewTip)
208		}
209		if got := r.resolveRef("refs/heads/main"); got != resultSHA {
210			t.Errorf("main tip = %s, want %s", got, resultSHA)
211		}
212		if n := r.mergeCommitCount("refs/heads/main"); n != 0 {
213			t.Errorf("expected 0 merge commits on main on ff path, got %d", n)
214		}
215		// Replay fidelity: the worker commit's parent must still be BaseRev.
216		parents := r.commitParents(resultSHA)
217		if len(parents) != 1 || parents[0] != r.baseSHA {
218			t.Errorf("worker commit parent = %v, want [%s]", parents, r.baseSHA)
219		}
220		// Worktree sync: feature.txt must exist on disk in the main worktree
221		// after Land() (bug ddx-eaebaffb regression test — pre-fix, the file
222		// was in the index but missing from disk because update-ref bypassed
223		// the working tree).
224		featurePath := filepath.Join(r.dir, "feature.txt")
225		content, readErr := os.ReadFile(featurePath)
226		if readErr != nil {
227			t.Errorf("feature.txt not materialized in working tree after Land(): %v", readErr)
228		} else if string(content) != "hello\n" {
229			t.Errorf("feature.txt content = %q, want %q", string(content), "hello\n")
230		}
231		// git status should show NO phantom deleted/modified entries for feature.txt.
232		statusOut := r.runGit("status", "--porcelain", "feature.txt")
233		if strings.TrimSpace(statusOut) != "" {
234			t.Errorf("git status after Land() shows unexpected entry for feature.txt: %q", statusOut)
235		}
236	}
